import{_ as s,o as t,c as i,ae as e}from"./chunks/framework.D6sYw4vw.js";const _=JSON.parse('{"title":"Julia换源(更换国内镜像站)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/92Workflow/julia_change_pkgserve.md","filePath":"docs/92Workflow/julia_change_pkgserve.md","lastUpdated":1773485796000}'),l={name:"docs/92Workflow/julia_change_pkgserve.md"};function p(r,a,c,n,o,d){return t(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="julia换源-更换国内镜像站" tabindex="-1">Julia换源(更换国内镜像站) <a class="header-anchor" href="#julia换源-更换国内镜像站" aria-label="Permalink to &quot;Julia换源(更换国内镜像站)&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><pre><code>Contents：JuliaPkg

Contributor: YJY

Email:522432938@qq.com

如有错误，请批评指正。
</code></pre><ol><li><p>打开julia的安装路径，找到文件夹 julia-1.x.x(如1.6.1) 如图 <img src="https://img-blog.csdnimg.cn/303b28feddd74bbb97ea3ab07dd9183c.png" alt="在这里插入图片描述"></p></li><li><p>进入该文件夹找到etc <img src="https://img-blog.csdnimg.cn/5728ccd73bd14b27a1848b4d5291048f.png?x-oss-process=image/watermark,type_ZHJvaWRzYW5zZmFsbGJhY2s,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16" alt="在这里插入图片描述"></p></li><li><p>进入etc 再进入一个文件夹，有一个startup.jl <img src="https://img-blog.csdnimg.cn/5288a19b5c8445b78cddc8bd9bc6448d.png" alt="在这里插入图片描述"></p></li></ol><p><strong>这个startup.jl就很方便了，在启动julia的时候，会首先自动运行里面的内容</strong>。</p><p>所以，打开它，在里面输入一行</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ENV</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;JULIA_PKG_SERVER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://mirrors.pku.edu.cn/julia/&quot;</span></span></code></pre></div><p>就像这样 <img src="https://img-blog.csdnimg.cn/95077d4c254942c2b637d4f926e652ed.png" alt="在这里插入图片描述"> 保存就完事了。</p><p>ENV是julia的全局环境变量，能够直接在repl中修改环境变量，但不是永久的。所以放在startup.jl里。这样等价于永久改变了，因为每次启动都会repl自动执行它。</p><p>在repl中输入ENV如下： <img src="https://img-blog.csdnimg.cn/b2ff78c2cd40404bbc4ab667ae11c241.png?x-oss-process=image/watermark,type_ZHJvaWRzYW5zZmFsbGJhY2s,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16" alt="在这里插入图片描述"></p><p>还有一些其它的比如LOAD_PATH 和DEPOT_PATH等等，这些都是环境变量。更多可以看<a href="https://docs.juliacn.com/latest/manual/environment-variables/" target="_blank" rel="noreferrer">中文文档</a><img src="https://img-blog.csdnimg.cn/2c1e899b55884b6eb0b0afb7df788d5d.png?x-oss-process=image/watermark,type_ZHJvaWRzYW5zZmFsbGJhY2s,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16" alt="在这里插入图片描述"></p><p>PS: 不换也行，最新版的julia好像能自动选取一个最快的源。</p></div>`,2)])])}const h=s(l,[["render",p]]);export{_ as __pageData,h as default};
